// The simplest possible React component
function Greeting() {
  return <h1>Hello, world!</h1>;
}

// A component that accepts data
function UserCard({ name, avatarUrl }: { name: string; avatarUrl: string }) {
  return (
    <div className="card">
      <img src={avatarUrl} alt={name} />
      <p>{name}</p>
    </div>
  );
}

// What you write:
const element = <h1 className="title">Hello</h1>;

// What the compiler produces (React 17+ JSX transform):
import { jsx as _jsx } from 'react/jsx-runtime';
const element = _jsx('h1', { className: 'title', children: 'Hello' });

function ProductList({ products }: { products: Product[] }) {
  return (
    <ul>
      {products.map((product) => (
        <li key={product.id}>
          {product.name} — ${product.price.toFixed(2)}
        </li>
      ))}
    </ul>
  );
}

interface ButtonProps {
  label: string;
  variant?: 'primary' | 'secondary';
  disabled?: boolean;
  onClick: () => void;
}

function Button({ label, variant = 'primary', disabled = false, onClick }: ButtonProps) {
  return (
    <button
      className={`btn btn-${variant}`}
      disabled={disabled}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

// Usage
<Button label="Save" onClick={handleSave} />
<Button label="Delete" variant="secondary" onClick={handleDelete} />

// The 'children' prop is special — it holds nested JSX
function Card({ children }: { children: React.ReactNode }) {
  return <div className="card">{children}</div>;
}

// Nesting content inside Card
<Card>
  <h2>Title</h2>
  <p>Some content here</p>
</Card>

import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0); // initial value = 0

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>+</button>
      <button onClick={() => setCount(count - 1)}>−</button>
      <button onClick={() => setCount(0)}>Reset</button>
    </div>
  );
}

function SnapshotDemo() {
  const [count, setCount] = useState(0);

  function handleClick() {
    // Both lines read the same snapshot — count is 0 when button first clicked
    setCount(count + 1); // schedules: 0 + 1 = 1
    setCount(count + 1); // schedules: 0 + 1 = 1 (NOT 2!)
    // Result: count becomes 1, not 2
  }

  // Fix: use functional update form to reference previous value
  function handleClickFixed() {
    setCount(prev => prev + 1); // 0 → 1
    setCount(prev => prev + 1); // 1 → 2
    // Result: count becomes 2
  }

  return <button onClick={handleClick}>{count}</button>;
}

// Imperative (vanilla JS) — you manage the DOM manually
const btn = document.getElementById('like-btn');
let liked = false;
btn.addEventListener('click', () => {
  liked = !liked;
  btn.textContent = liked ? 'Unlike' : 'Like';
  btn.classList.toggle('liked', liked);
  document.getElementById('count').textContent = String(parseInt(count.textContent) + (liked ? 1 : -1));
});

// Declarative (React) — describe the end state
function LikeButton({ count }: { count: number }) {
  const [liked, setLiked] = useState(false);
  return (
    <button className={liked ? 'liked' : ''} onClick={() => setLiked(!liked)}>
      {liked ? 'Unlike' : 'Like'} ({liked ? count + 1 : count})
    </button>
  );
}

// Parent owns the state
function SearchPage() {
  const [query, setQuery] = useState('');

  return (
    <div>
      {/* Pass data down and update function down */}
      <SearchInput value={query} onChange={setQuery} />
      <SearchResults query={query} />
    </div>
  );
}

// Child receives and reports changes — never mutates parent state directly
function SearchInput({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  return (
    <input
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder="Search..."
    />
  );
}

// Small, focused components compose into larger ones
function Avatar({ src, alt }: { src: string; alt: string }) {
  return <img className="avatar" src={src} alt={alt} />;
}

function UserName({ name }: { name: string }) {
  return <span className="user-name">{name}</span>;
}

function UserBadge({ user }: { user: User }) {
  return (
    <div className="badge">
      <Avatar src={user.avatarUrl} alt={user.name} />
      <UserName name={user.name} />
    </div>
  );
}

// Composed into the app
function Header({ currentUser }: { currentUser: User }) {
  return (
    <header>
      <nav>...</nav>
      <UserBadge user={currentUser} />
    </header>
  );
}

// Too much in one component
function ProductPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [filter, setFilter] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [user, setUser] = useState<User | null>(null);
  // ... 300 lines of mixed concerns
}

// Better: split by concern
function ProductPage() {
  return (
    <div className="page">
      <UserHeader />           {/* owns user state */}
      <FilterBar />             {/* owns filter state */}
      <ProductGrid />           {/* owns product list */}
      <CartSidebar />           {/* owns cart state */}
    </div>
  );
}

// WRONG — mutates state in place; React does not re-render
const [items, setItems] = useState([1, 2, 3]);
function addItem() {
  items.push(4);       // mutation! React sees the same array reference
  setItems(items);     // no-op as far as React is concerned
}

// CORRECT — replace with a new array
function addItem() {
  setItems([...items, 4]); // new array reference → React re-renders
}

// WRONG — fullName is redundant state that can get out of sync
const [firstName, setFirstName] = useState('');
const [lastName, setLastName] = useState('');
const [fullName, setFullName] = useState(''); // should not be state

// CORRECT — derive during render
const [firstName, setFirstName] = useState('');
const [lastName, setLastName] = useState('');
const fullName = `${firstName} ${lastName}`.trim(); // computed, not stored

// WRONG — no key (or using index as key for a sortable list)
{items.map((item, index) => <Item key={index} item={item} />)}

// CORRECT — use a stable, unique identifier
{items.map((item) => <Item key={item.id} item={item} />)}

// WRONG — InnerList is redefined on every render of OuterList
function OuterList({ items }: { items: Item[] }) {
  function InnerList() { // new function reference each render
    return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
  }
  return <InnerList />; // React unmounts and remounts on every render
}

// CORRECT — define at module level or extract to its own file
function InnerList({ items }: { items: Item[] }) {
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}
function OuterList({ items }: { items: Item[] }) {
  return <InnerList items={items} />;
}
